import{_ as e,a as r,b as o,c as t,d as i,e as d}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as l,o as n,c,a2 as s}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Añadir un canal Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"es/upload/dropbox.md","filePath":"es/upload/dropbox.md","lastUpdated":1781962217000}'),p={name:"es/upload/dropbox.md"};function b(u,a,h,m,g,x){return n(),c("div",null,[...a[0]||(a[0]=[s('<h1 id="anadir-un-canal-dropbox" tabindex="-1">Añadir un canal Dropbox <a class="header-anchor" href="#anadir-un-canal-dropbox" aria-label="Permalink to &quot;Añadir un canal Dropbox&quot;">​</a></h1><p>El canal Dropbox usa una cuenta de Dropbox como destino de almacenamiento.</p><h2 id="que-preparar" tabindex="-1">Qué preparar <a class="header-anchor" href="#que-preparar" aria-label="Permalink to &quot;Qué preparar&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requisito</th><th>Uso</th></tr></thead><tbody><tr><td>Cuenta de Dropbox</td><td>Guardar archivos</td></tr><tr><td>Dropbox App</td><td>Dar acceso por API</td></tr><tr><td>Access Token</td><td>Permitir que ImgBed use Dropbox</td></tr><tr><td>Directorio</td><td>Opcional, normalmente <code>imgbed</code></td></tr></tbody></table><h2 id="crear-la-aplicacion" tabindex="-1">Crear la aplicación <a class="header-anchor" href="#crear-la-aplicacion" aria-label="Permalink to &quot;Crear la aplicación&quot;">​</a></h2><p>Abre Dropbox App Console y crea una aplicación nueva.</p><p><img src="'+e+'" alt="Crear aplicación" loading="lazy"></p><p>Elige el alcance según cómo quieras guardar los archivos. Una carpeta dedicada suele ser más fácil de mantener.</p><h2 id="configurar-callback" tabindex="-1">Configurar callback <a class="header-anchor" href="#configurar-callback" aria-label="Permalink to &quot;Configurar callback&quot;">​</a></h2><p>Si usas OAuth, añade la URL de retorno de ImgBed:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://tu-dominio/api/oauth/dropbox/callback</span></span></code></pre></div><p><img src="'+r+'" alt="Configurar callback" loading="lazy"></p><h2 id="anadir-permisos" tabindex="-1">Añadir permisos <a class="header-anchor" href="#anadir-permisos" aria-label="Permalink to &quot;Añadir permisos&quot;">​</a></h2><p>Activa permisos de subida, lectura y borrado según necesite ImgBed.</p><p><img src="'+o+'" alt="Permisos Dropbox" loading="lazy"></p><h2 id="obtener-token" tabindex="-1">Obtener Token <a class="header-anchor" href="#obtener-token" aria-label="Permalink to &quot;Obtener Token&quot;">​</a></h2><p>Obtén el token desde la aplicación o desde el flujo de autorización de ImgBed.</p><p><img src="'+t+'" alt="Obtener Token" loading="lazy"></p><p>Copia el token y pégalo en ImgBed.</p><p><img src="'+i+'" alt="Copiar Token" loading="lazy"></p><h2 id="rellenar-en-imgbed" tabindex="-1">Rellenar en ImgBed <a class="header-anchor" href="#rellenar-en-imgbed" aria-label="Permalink to &quot;Rellenar en ImgBed&quot;">​</a></h2><p>En Configuración de subida, elige <code>Dropbox</code>.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Valor</th></tr></thead><tbody><tr><td>Nombre del canal</td><td>Nombre reconocible</td></tr><tr><td>Access Token</td><td>Token de Dropbox</td></tr><tr><td>Directorio</td><td>Opcional; vacío o <code>imgbed</code></td></tr><tr><td>Nota</td><td>Opcional</td></tr></tbody></table><h2 id="verificacion" tabindex="-1">Verificación <a class="header-anchor" href="#verificacion" aria-label="Permalink to &quot;Verificación&quot;">​</a></h2><p>Después de guardar, ejecuta consulta de capacidad o sube una imagen de prueba.</p><p><img src="'+d+'" alt="Consulta de capacidad" loading="lazy"></p><p>Si el archivo aparece en Dropbox y el enlace de ImgBed abre correctamente, el canal está listo.</p><h2 id="que-revisar-si-falla" tabindex="-1">Qué revisar si falla <a class="header-anchor" href="#que-revisar-si-falla" aria-label="Permalink to &quot;Qué revisar si falla&quot;">​</a></h2><ul><li>Token caducado o con permisos incompletos.</li><li>Cambiaste permisos de la app pero no volviste a autorizar.</li><li>Directorio con espacios o barras innecesarias.</li><li>Dropbox sin espacio disponible.</li></ul>',29)])])}const q=l(p,[["render",b]]);export{k as __pageData,q as default};
